import java.util.ArrayList;
import java.util.Collections;

public int eliminateMonsters(int[] dist, int[] speed) {
    int n = dist.length;
    ArrayList<Double> timeToReach = new ArrayList<>();
    for (int i = 0; i < n; ++i) {
        timeToReach.add(dist[i] / (double) speed[i]);
    }
    Collections.sort(timeToReach);
    int monstersEliminated = 0;
    for (int i = 0; i < n; ++i) {
        if (monstersEliminated < timeToReach.get(i)) {
            monstersEliminated++;
        }
    }
    return monstersEliminated;
}
```

